def dedupe_results(results, keep_recent=3):
    """
    去重契约：保留每个 path 的最新一次读取，同时无条件保留全局最近三条，二者取并集。
    副作用契约：返回新字典列表，不得原地修改调用方传入的 results。
    """
    # 1. 找出每个 path 最后一次出现的索引（从后往前扫描）
    latest_per_path = {}
    for idx, item in enumerate(results):
        path = item.get("path")
        if path is not None:
            latest_per_path[path] = idx

    # 2. 全局最近三条的索引集合
    recent_indices = set(range(max(0, len(results) - keep_recent), len(results)))

    # 3. 每个 path 最新读取的索引集合
    path_indices = set(latest_per_path.values())

    # 4. 并集：需要保留完整内容的索引
    keep_indices = recent_indices | path_indices

    # 5. 构造新列表，不修改原 results
    return [
        item if idx in keep_indices else {**item, "content": SNIPPED}
        for idx, item in enumerate(results)
    ]

