def truncate_utf8(text, max_bytes):
    """Truncate text to fit within max_bytes UTF-8 bytes.

    - If text fits within max_bytes, return it unchanged.
    - Otherwise, truncate at a UTF-8 safe boundary, preserving
      the beginning and end with a "...[truncated]..." marker.
    - The result must always be valid UTF-8 and never exceed max_bytes.
    """
    encoded = text.encode('utf-8')
    if len(encoded) <= max_bytes:
        return text

    # For very small budgets, just truncate bytes safely
    if max_bytes < 20:
        while max_bytes > 0:
            try:
                return encoded[:max_bytes].decode('utf-8')
            except UnicodeDecodeError:
                max_bytes -= 1
        return ''

    marker = '...[truncated]...'
    marker_encoded = marker.encode('utf-8')
    marker_len = len(marker_encoded)

    # Reserve space for marker
    available = max_bytes - marker_len
    if available < 2:
        # Not enough room for marker + any content; just truncate bytes safely
        while max_bytes > 0:
            try:
                return encoded[:max_bytes].decode('utf-8')
            except UnicodeDecodeError:
                max_bytes -= 1
        return ''

    # Split budget roughly evenly between head and tail
    head_budget = available // 2
    tail_budget = available - head_budget

    # Find safe UTF-8 boundary for head
    head_bytes = encoded[:head_budget]
    while head_bytes:
        try:
            head_text = head_bytes.decode('utf-8')
            break
        except UnicodeDecodeError:
            head_bytes = head_bytes[:-1]
    else:
        head_text = ''

    # Find safe UTF-8 boundary for tail
    tail_bytes = encoded[-tail_budget:]
    while tail_bytes:
        try:
            tail_text = tail_bytes.decode('utf-8')
            break
        except UnicodeDecodeError:
            tail_bytes = tail_bytes[1:]
    else:
        tail_text = ''

    result = head_text + marker + tail_text
    # Final safety check: ensure result fits within max_bytes
    while len(result.encode('utf-8')) > max_bytes:
        if len(head_text) > len(tail_text):
            head_text = head_text[:-1]
        else:
            tail_text = tail_text[:-1]
        result = head_text + marker + tail_text
    return result

