        is_latest_per_path = (seen.get(path) == idx)
        is_recent = (idx >= recent_cutoff)
        if is_latest_per_path or is_recent:
            new_results.append(dict(item))  # 浅拷贝，不修改原对象
        else:
            new_results.append({**item, "content": SNIPPED})
    return new_results
